<style>
/* ===== 基础变量 ===== */
:root{
  --bg:#0f0a1a;
  --bg2:#1a0f2e;
  --bg3:#251240;
  --card:rgba(30,20,50,0.85);
  --card-h:rgba(45,30,75,0.9);
  --text:#f0e8ff;
  --text-dim:#a090c0;
  --gold:#ffd700;
  --gold-light:#ffec8b;
  --purple:#c084fc;
  --purple-dim:#9d4edd;
  --border:rgba(192,132,252,0.25);
  --border-h:rgba(255,215,0,0.5);
  --accent:#c084fc;
  --success:#4ade80;
  --danger:#f87171;
  --shadow:0 4px 20px rgba(0,0,0,0.5);
  --shadow-gold:0 0 30px rgba(255,215,0,0.3);
  --transition:all 0.3s cubic-bezier(0.4,0,0.2,1)
}

/* ===== 基础重置 ===== */
*{margin:0;padding:0;box-sizing:border-box}

/* ===== 背景纹理 ===== */
body{
  font-family:'Cinzel','Noto Serif SC','Microsoft YaHei',serif;
  background:linear-gradient(160deg,var(--bg) 0%,var(--bg2) 40%,var(--bg3) 100%);
  color:var(--text);
  min-height:100vh;
  display:flex;
  justify-content:center;
  align-items:center;
  padding:20px;
  position:relative
}
body::before{
  content:'';
  position:fixed;
  top:0;left:0;right:0;bottom:0;
  background:radial-gradient(ellipse at 30% 20%,rgba(157,78,221,0.12) 0%,transparent 50%),
             radial-gradient(ellipse at 70% 80%,rgba(192,132,252,0.08) 0%,transparent 50%);
  pointer-events:none;
  z-index:0
}

/* ===== 主容器 ===== */
.C{
  max-width:900px;
  width:100%;
  background:linear-gradient(145deg,rgba(20,12,40,0.9),rgba(30,18,55,0.85));
  border-radius:24px;
  border:1px solid var(--border);
  padding:32px;
  box-shadow:var(--shadow),0 0 60px rgba(192,132,252,0.1);
  position:relative;
  z-index:1;
  backdrop-filter:blur(10px)
}


/* ===== 标题区域 ===== */
.tb{text-align:center;margin-bottom:28px;padding:20px 16px;border-bottom:1px solid var(--border);position:relative}
.tb::after{
  content:'';
  position:absolute;
  bottom:-1px;left:50%;transform:translateX(-50%);
  width:120px;height:2px;
  background:linear-gradient(90deg,transparent,var(--gold),transparent)
}
.tb h1{
  font-size:32px;
  font-weight:700;
  letter-spacing:12px;
  margin-bottom:8px;
  background:linear-gradient(135deg,var(--gold) 0%,var(--gold-light) 50%,var(--gold) 100%);
  -webkit-background-clip:text;
  -webkit-text-fill-color:transparent;
  filter:drop-shadow(0 0 12px rgba(255,215,0,0.5));
  text-transform:uppercase
}
.tb .sub{color:var(--text-dim);font-size:11px;letter-spacing:4px;text-transform:uppercase}

/* ===== 步骤指示器 ===== */
.si{display:flex;justify-content:center;gap:12px;margin-bottom:24px}
.sd{width:12px;height:12px;border-radius:50%;background:rgba(255,255,255,0.1);border:2px solid transparent;transition:var(--transition);position:relative}
.sd::after{
  content:'';
  position:absolute;
  top:50%;left:50%;transform:translate(-50%,-50%);
  width:4px;height:4px;border-radius:50%;background:transparent;transition:var(--transition)
}
.sd.active{background:var(--gold);border-color:var(--gold);box-shadow:0 0 15px rgba(255,215,0,0.6)}
.sd.active::after{background:var(--bg)}
.sd.done{background:var(--purple-dim);border-color:var(--purple)}

/* ===== 屏幕切换 ===== */
.screen{display:none;animation:fadeIn 0.4s ease}
.screen.active{display:block}
@keyframes fadeIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}

/* ===== 屏幕标题 ===== */
.st{
  font-size:22px;
  font-weight:700;
  margin-bottom:20px;
  color:var(--gold);
  text-shadow:0 0 20px rgba(255,215,0,0.4);
