}
.faction-desc .desc-title{color:var(--purple);font-weight:600;margin-bottom:6px;font-size:14px}

/* ===== 选项列表 ===== */
.opt-list{display:flex;flex-direction:column;gap:12px;margin-bottom:20px}
.opt{
  padding:16px 22px;
