  background:var(--card);
  border:1px solid var(--border);
  cursor:pointer;
  transition:var(--transition);
  font-size:15px;
  color:var(--text);
  display:flex;
  align-items:center;
  gap:14px;
  position:relative;
  overflow:hidden
}
.opt::before{
  content:'';
