  transform:translateX(8px);
  box-shadow:var(--shadow-gold)
}
.opt .ic{font-size:24px;width:36px;text-align:center;flex-shrink:0;filter:drop-shadow(0 0 5px rgba(255,215,0,0.3))}
.opt .lb{flex:1;font-weight:500}
.opt .ds{font-size:11px;color:var(--text-dim);margin-top:3px;letter-spacing:0.5px}

/* ===== 角色网格 - 桌面3列 ===== */
.hero-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-bottom:20px}

/* ===== 角色卡片 ===== */
.hc{
  padding:18px 14px;
  border-radius:16px;
  background:linear-gradient(145deg,var(--card),rgba(40,25,70,0.9));
  border:1px solid var(--border);
  box-shadow:var(--shadow),inset 0 1px 0 rgba(255,255,255,0.03);
  cursor:pointer;
  transition:var(--transition);
  text-align:center;
  position:relative;
  overflow:hidden
}
.hc::after{
  content:'';
  position:absolute;
  top:0;left:-100%;width:100%;height:100%;
  background:linear-gradient(90deg,transparent,rgba(255,215,0,0.1),transparent);
  transition:left 0.5s ease
}
.hc:hover::after{left:100%}
.hc:hover{
  transform:translateY(-4px);
  box-shadow:0 12px 30px rgba(0,0,0,0.4),0 0 25px rgba(192,132,252,0.4);
  border-color:var(--border-h);
  background:var(--card-h)
}
.hc.selected{
  border-color:var(--gold);
  box-shadow:0 0 30px rgba(255,215,0,0.3),inset 0 0 20px rgba(255,215,0,0.1)
}
.hc .hn{
  font-size:16px;
  font-weight:700;
  color:var(--gold);
  margin-bottom:5px;
  text-shadow:0 0 10px rgba(255,215,0,0.4);
  letter-spacing:1px
}
.hc .ha{
  font-size:11px;
  color:var(--purple);
  margin-bottom:8px;
  font-style:italic;
  letter-spacing:1.5px;
  text-transform:uppercase
}
.hc .hd{
  font-size:10px;
  color:var(--text-dim);
  margin-top:6px;
  line-height:1.5;
  background:rgba(192,132,252,0.08);
  padding:8px 10px;
  border-radius:10px;
  border:1px solid rgba(192,132,252,0.1)
}
.hc.custom{grid-column:1/-1;padding:16px;display:flex;align-items:center;gap:16px;text-align:left;border-style:dashed;border-color:rgba(255,215,0,0.3)}
.hc.custom .hn{font-size:16px}.hc.custom .ha{font-size:12px}

/* ===== 表单 ===== */
.fm{display:flex;flex-direction:column;gap:14px;margin-bottom:20px}
.fm-row{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}
.fm-row-2{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}
.fm-row-1{display:block}
.fg label{display:block;font-size:12px;color:var(--text-dim);margin-bottom:6px;letter-spacing:1px;text-transform:uppercase}
