}
.fg select{cursor:pointer}.fg select option{background:var(--bg2);color:var(--text)}
.fg textarea{resize:vertical;min-height:60px}

/* ===== 按钮 ===== */
.btn-row{display:flex;gap:14px;margin-top:24px;justify-content:center;flex-wrap:wrap}
.btn{
  padding:14px 32px;
  border-radius:12px;
  background:linear-gradient(135deg,rgba(192,132,252,0.15),rgba(255,215,0,0.08));
  border:1px solid var(--border);
  color:var(--gold);
  font-weight:600;
  cursor:pointer;
  transition:var(--transition);
  font-family:inherit;
  font-size:14px;
  letter-spacing:1px;
  position:relative;
  overflow:hidden
}
.btn::before{
  content:'';
  position:absolute;
  top:50%;left:50%;transform:translate(-50%,-50%) scale(0);
  width:100%;height:100%;
  background:
  transition:transform 0.3s ease
}
.btn:hover::before{transform:translate(-50%,-50%) scale(1)}
.btn:hover{
  border-color:var(--gold);
  box-shadow:var(--shadow-gold);
  transform:translateY(-2px)
}
.btn-p{
