/* ===== 摘要框 ===== */
.summary-box{
  background:rgba(0,0,0,0.25);
  border:1px solid var(--border);
  border-radius:14px;
  padding:20px;
  margin-bottom:20px;

}
.summary-section{margin-bottom:20px}
.summary-section h3{color:var(--gold);font-size:14px;margin-bottom:12px;border-bottom:1px solid var(--border);padding-bottom:8px;letter-spacing:1px}
.summary-item{display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid rgba(255,255,255,0.05)}
.summary-item:last-child{border-bottom:none}
.summary-label{color:var(--text-dim);font-size:12px}
.summary-value{color:var(--text);font-size:13px;text-align:right;flex:1;margin-left:12px}

/* ===== 自定义区域 ===== */
.custom-full textarea{}
.custom-section{
  background:linear-gradient(90deg,rgba(255,215,0,0.08),transparent);
  border-left:3px solid var(--gold);
  padding:14px;
  margin-top:14px;
  border-radius:0 12px 12px 0
}
.demon-custom{margin-bottom:20px}
